import{_ as n,o as r,c as t,ag as i}from"./chunks/framework.DXGyWiRo.js";const a="/images/uebung068.jpg",s="/images/uebung069.jpg",b=JSON.parse('{"title":"Übung Lektion 42","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung42.md","filePath":"lektionen/uebung42.md"}'),o={name:"lektionen/uebung42.md"};function l(u,e,p,h,c,d){return r(),t("div",null,[...e[0]||(e[0]=[i('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-42" tabindex="-1">Übung Lektion 42 <a class="header-anchor" href="#ubung-lektion-42" aria-label="Permalink to &quot;Übung Lektion 42&quot;">​</a></h1><p>Übersetzen Sie:</p><p>प्रकृत्यैव यः कर्माणि क्रियमाणानि पश्यति स आत्मानमकर्तरं पश्यति ॥१॥</p><blockquote><p>Wer sieht, dass nur die materielle Natur Taten bewirkt, der sieht, dass die Seele untätig ist.</p></blockquote><p>कृष्णस्तस्य लोकस्य पिता माता पितामहो धातास्ति ॥२॥</p><blockquote><p>Kṛṣṇa ist Vater, Mutter, Großvater und Schöpfer dieser Welt.</p></blockquote><p>आचार्याः पितरः पुत्राश्च पितामहाः श्वशुरा नप्तरो युद्धायावस्थिताः । एतान्न हन्तुमिच्छामीत्यर्जुनो भगवद्गीतायामुवाच ॥३॥</p><blockquote><p>&quot;Meine Lehrer, Väter, Söhne, Großväter, Schwiegerväter und Enkel haben sich zum Kampf aufgestellt. Ich will diese nicht töten!&quot; so sprach Arjuna in der Bhagavadgītā.</p></blockquote><p>कवयो लब्धपुत्रतायाः पितॄन्मातॄश्च तुष्टुवुः ॥४॥</p><blockquote><p>Dichter priesen Väter und Mütter, weil sie Söhne bekommen haben.</p></blockquote><p>भर्त्रा भार्या भर्तव्या । तस्माद्भार्येत्युच्यते ॥५॥</p><blockquote><p>Die Gattin muss vom Gatten erhalten werden. Deswegen wird sie &quot;zu Erhaltende (भार्या)&quot; genannt.</p></blockquote><p>सत्पुत्रः पितृभ्यः पिण्डान्ददाति । पितृभिः पिण्डदानमश्यत एवं च सुखजीवो जीवितुं शक्यते ॥६॥</p><blockquote><p>Ein guter Sohn gibt seinen Vorvätern Reisbällchen. Die Vorväter essen die dargebrachten Reisbällchen und so können sie ein glückliches Leben führen.</p></blockquote><p>भ्रात्रा स्वसा न विवोड्धव्या । भातरि स्वसारं कामयमाने देवाः क्रुध्यन्ति ॥७॥</p><blockquote><p>Ein Bruder darf seine Schwester nicht heiraten. Wenn ein Bruder seine Schwester begehrt, zürnen die Götter.</p></blockquote><p>क्थं भर्तुर्भ्रातोच्यते । देवेति भर्तुर्भ्राता वक्तव्यः ॥८॥</p><blockquote><p>Wie nennt man den Bruder des Gatten. Der Gattenbruder wird &quot;Schwager&quot; genannt.</p></blockquote><p>नप्तॄणां लाभं पितैच्छत् ॥९॥</p><blockquote><p>Der Vater wünschte, Enkel zu bekommen.</p></blockquote><p><img src="'+a+'" alt=""><br> Abb.: कृष्णस्तस्य लोकस्य पिता माता पितामहो धातास्ति<br> डूंगरपुर<br> [Bildquelle: Dey. -- <a href="http://www.flickr.com/photos/dey/2890614471/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/dey/2890614471/</a>. -- Zugriff am 2009-01-21. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>सीताविवाहः</p><p>पुरा मिथिलायां जनको नाम राजा बभूव । तस्य सुता सीता नाम । सा रूपे शीले चानुपमा बभूव । तां परिणेतुमिछ्हन्तो ऽनेके राजकुमारा जनकाय दूतान्प्रेषयामासुः ॥</p><p>जनकस्तु तां वीर्यसम्पन्नाय क्षत्रियकुमाराय दातुमैच्छत् । अतः स तां वीर्येण क्रेतव्यामकल्पयत् । तथा हि -- तस्य सकाशे गुरुतरं किमपि धनुरासीत् । य इदं धनुरुद्धृत्यास्मिन्शरं सन्धत्ते स मम सुतां परिणेष्यतीति जनकः प्रतिजज्ञे ॥</p><p>तां तस्य प्रतिज्ञां श्रुत्वा शतशो राजकुमाराः समाजग्मुः । परं नैको ऽपि तेषां तद्धनुश्चलयितुमपि शशाक । लङ्काधिपती रावणो ऽपि साटोपं समेत्य सलज्जं प्रतिनिवृत्त इति ज्ञायते ॥</p><p>सर्वान्राजकुमारान्प्रतिवृत्तान्विलोक्य को मे दुहितुर्भर्ता भविष्यतीति चिन्तापरो बभूव जनकः । अत्रान्तरे ऽयोध्याधिपतेर्दशरथस्य पुत्रः श्रीरामः सलक्ष्मणो विश्वा्मित्रेण तत्रानीयत । श्रीरामो महर्षेर्विश्वामित्रस्य वचनेन लीलयैव तद्धनुरुद्धृत्य यावत्तस्मिन्बाणमारोपयति तावत्तद्धनुर्द्वेधा भग्नं बभूव ॥</p><p>साधु साध्विति श्रीरामस्य वीर्यं प्रशशंसुर्जनाः ॥</p><p>जनकस्य राज्ञो हृदयं प्रहृष्टं बभूव । ततः स दशरथादीनानाय्य महता विभवेन सीतरामयोर्विवाहोत्सवं निरवर्तयन् ॥</p><p>(संस्कृतप्रथमादर्शे)</p><blockquote><p>Sītās Heirat</p><p>Einstmals gab es in Mithilā einen König namens Janaka. Er hatte eine Tochter namens Sītā. Sie war unvergleichlich an Schönheit und Tugend. Viele königliche Prinzen, die sie heiraten wollten, schickten zu Janaka Botschafter.</p><p>Janaka aber wollte sie einem königlichen Prinzen Geben, der voll Manneskraft ist. Deswegen bestimmte er, dass sie mit Manneskraft erkauft werden muss. Nämlich so: Er hatte in seinem Besitz einen sehr schweren Bogen. Janaka versprach, dass wer diesen Bogen hochhebt und auf ihn einen Pfeil legt, seine Tochter heirate.</p><p>Als sie dieses Versprechen hörten, kamen königliche Prinzen zu hunderten herbei. Aber kein einziger von ihnen konnte den Bogen auch nur bewegen. Man weiß, dass selbst Rāvaṇa, der Oberherrscher Laṅkās, voll Stolz kam und voll Scham zurückkehrte. Als er sah, dass alle königlichen Prinzen wieder zurückkehrten, versank Janaka in tiefe Sorge, wer Gatte seiner Tochter sein würde. Inzwischen führte Viśvāmitra den Rāma, den Sohn Daśarathas, des Herrschers von Ayodhyā, zusammen mit Lakṣmaṇa dorthin. Auf das Wort des großen Ṛṣi Viśvāmitra hob der herrliche Rāma den Bogen spielend leicht auf. Sobald er einen Pfeil darauf anlegte, zersprang der Bogen in zwei Teile.</p><p>&quot;Gut, gut&quot; lobten die Leute die Manneskraft des herrlichen Rāma.</p><p>Das Herz König Janakas wurde froh. Da ließ er Daśaratha und die anderen kommen und ließ die Hochzeit von Sītā und Rāma mit großem Prunk ausrichten.</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.: श्रीसीता श्रीरामश्च<br> दीवाली मेला, Manchester, 2006<br> [Bildquelle: BinaryApe. -- <a href="http://www.flickr.com/photos/binaryape/268134691/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/binaryape/268134691/</a>. -- Zugriff am 2009-01-21. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung)]</p>',32)])])}const m=n(o,[["render",l]]);export{b as __pageData,m as default};
